class Playground {
    async run(inputs) {
        const n = parseInt(inputs[0]);
        if (isNaN(n) || n <= 0) {
            this.log("Please enter a positive integer for N.");
            return [];
        }

        // Initialize the chessboard grid with empty cells
        this.grid.init(Array(n).fill(0).map(() => Array(n).fill('')));
        this.callstack.init();
        this.recursionTree.init();
        this.variables.init([['N', n], ['solutionsCount', 0]]);

        // board array stores the column index of the queen for each row
        // board[row] = col; -1 means no queen in that row
        const board = new Array(n).fill(-1);
        const solutions = [];

        // Helper function to check if placing a queen at (r, c) is safe
        const isValid = async (r, c) => {
            this.log(`Checking if queen at (${r}, ${c}) is safe.`);
            this.grid.highlight(r, c, '#00e0ff'); // Highlight current cell being checked (blue)
            await this.await();

            for (let prevRow = 0; prevRow < r; prevRow++) {
                const prevCol = board[prevRow];

                // Highlight previously placed queen for comparison (yellow)
                this.grid.highlight(prevRow, prevCol, '#ffb703');
                await this.await();

                // Check column conflict
                if (prevCol === c) {
                    this.log(`Conflict: Same column at (${prevRow}, ${prevCol})`);
                    this.grid.highlight(prevRow, prevCol, '#ff0000'); // Red for conflict
                    this.grid.highlight(r, c, '#ff0000'); // Red for conflict
                    await this.await();
                    this.grid.highlight(prevRow, prevCol, '#00f5a0'); // Revert placed queen to green
                    this.grid.highlight(r, c, '#ffffff'); // Clear current cell highlight
                    return false;
                }
                // Check diagonal conflict
                if (Math.abs(prevRow - r) === Math.abs(prevCol - c)) {
                    this.log(`Conflict: Diagonal at (${prevRow}, ${prevCol})`);
                    this.grid.highlight(prevRow, prevCol, '#ff0000'); // Red for conflict
                    this.grid.highlight(r, c, '#ff0000'); // Red for conflict
                    await this.await();
                    this.grid.highlight(prevRow, prevCol, '#00f5a0'); // Revert placed queen to green
                    this.grid.highlight(r, c, '#ffffff'); // Clear current cell highlight
                    return false;
                }
                // If no conflict with this prevRow, revert its highlight to green
                this.grid.highlight(prevRow, prevCol, '#00f5a0');
                await this.await();
            }
            this.log(`Position (${r}, ${c}) is safe.`);
            this.grid.highlight(r, c, '#ffffff'); // Clear current cell highlight (blue)
            return true;
        };

        // Main backtracking function
        const solve = async (row) => {
            this.callstack.pushFrame('solve', { row: row });
            const nodeId = this.recursionTree.enterNode(`solve(row=${row})`);
            await this.await();

            // Base case: All queens are placed successfully
            if (row === n) {
                this.log(`Found a solution!`);
                // Deep copy the board to store the solution
                const currentSolution = board.map((col) => {
                    const rowArr = new Array(n).fill('.');
                    if (col !== -1) rowArr[col] = 'Q';
                    return rowArr.join('');
                });
                solutions.push(currentSolution);
                this.variables.put('solutionsCount', solutions.length);
                this.recursionTree.exitNode('#00f5a0'); // Green for success
                this.callstack.popFrame(currentSolution);
                await this.await();
                return;
            }

            // Try placing a queen in each column of the current row
            for (let col = 0; col < n; col++) {
                this.log(`Attempting to place queen at (${row}, ${col})`);
                this.grid.highlight(row, col, '#00e0ff'); // Highlight current cell being considered
                await this.await();

                if (await isValid(row, col)) {
                    this.log(`Valid placement. Placing queen at (${row}, ${col})`);
                    board[row] = col; // Place queen
                    this.grid.setCell(row, col, 'Q');
                    this.grid.highlight(row, col, '#00f5a0'); // Green for placed queen
                    await this.await();

                    await solve(row + 1); // Recurse for the next row

                    // Backtrack: Remove the queen and try next column
                    this.log(`Backtracking from (${row}, ${col})`);
                    board[row] = -1; // Remove queen
                    this.grid.setCell(row, col, '');
                    this.grid.highlight(row, col, '#ffb703'); // Orange for backtracked queen
                    await this.await();
                    this.grid.highlight(row, col, '#ffffff'); // Clear highlight
                    await this.await();
                } else {
                    this.log(`Invalid placement at (${row}, ${col}). Trying next column.`);
                    // isValid already handles highlighting conflicts, just clear the current cell highlight
                    this.grid.highlight(row, col, '#ffffff'); 
                    await this.await();
                }
            }
            this.recursionTree.exitNode(); // Mark node as finished
            this.callstack.popFrame();
            await this.await();
        };

        this.log("Starting N-Queens solver...");
        await solve(0); // Start with the first row (row 0)

        this.log(`Finished N-Queens solver. Found ${solutions.length} solutions.`);
        return solutions;
    }
}
